 82→            setHasRisk(hasRiskAccess(roles));
 83→            setHasReq(hasReqAccess(roles));
 84→            setUserRoles(roles);
 85→        }
 86→
 87→        // Check on mount
 88→        checkRoles();
 89→
 90→        // Listen for user data updates
 91→        window.addEventListener('userLoaded', checkRoles);
 92→
 93→        // Cleanup listener on unmount
 94→        return () => window.removeEventListener('userLoaded', checkRoles);
 95→    }, []);
 96→
 97→    // Connect to real-time SSE updates for exception approval badge
 98→    // Feature: 031-vuln-exception-approval, Phase 6: Real-Time Badge Updates
 99→    useEffect(() => {
