101→        const canApprove = userRoles.includes('ADMIN') || userRoles.includes('SECCHAMPION');
102→        if (!canApprove) {
103→            // Reset count if user doesn't have permission
104→            setPendingExceptionCount(0);
105→            return;
106→        }
107→
108→        // Connect to SSE endpoint for real-time count updates
109→        const disconnect = connectToBadgeUpdates((count) => {
110→            setPendingExceptionCount(count);
111→        });
112→
113→        // Cleanup on unmount or when roles change
114→        return () => {
115→            disconnect();
116→        };
117→    }, [userRoles.join(',')]); // Re-connect only when actual role membership changes
