 54→  const [totalPages, setTotalPages] = useState(0);
 55→  const [totalElements, setTotalElements] = useState(0);
 56→  const [pageSize] = useState(20);
 57→
 58→  // Filter state
 59→  const [emailFilter, setEmailFilter] = useState('');
 60→  const [domainFilter, setDomainFilter] = useState('');
 61→
 62→  // Toast notifications
 63→  const [toasts, setToasts] = useState<Toast[]>([]);
 64→  const [nextToastId, setNextToastId] = useState(1);
 65→
 66→  // Load mappings on mount and when filters/pagination/tabs change
 67→  useEffect(() => {
 68→    if (activeTab === 'manage' && viewMode === 'list') {
 69→      loadMappings();
