 71→  }, [activeTab, viewMode, currentPage, emailFilter, domainFilter, mappingViewTab]);
 72→
 73→  /**
 74→   * Load mappings from backend based on current tab selection
 75→   * Feature 042: Routes to different endpoints based on mappingViewTab
 76→   */
 77→  const loadMappings = async () => {
 78→    setIsLoading(true);
 79→    try {
 80→      let response;
 81→
 82→      if (mappingViewTab === 'current') {
 83→        // Load current mappings (future + active)
 84→        response = await listCurrentMappings(currentPage, pageSize);
 85→      } else {
 86→        // Load applied history
 87→        response = await listAppliedHistory(currentPage, pageSize);
 88→      }
 89→
 90→      setMappings(response.content);
