175→
176→  /**
177→   * Handle form cancel
178→   */
179→  const handleFormCancel = () => {
180→    setViewMode('list');
181→    setEditingMapping(undefined);
182→  };
183→
184→  /**
185→   * Handle page change
186→   */
187→  const handlePageChange = (page: number) => {
188→    setCurrentPage(page);
189→  };
190→
191→  /**
192→   * Handle filter change
193→   */
194→  const handleFilterChange = () => {
195→    setCurrentPage(0); // Reset to first page when filtering
196→  };
197→
198→  /**
