206→        return 'bi-exclamation-circle-fill';
207→      case 'info':
208→        return 'bi-info-circle-fill';
209→      default:
210→        return 'bi-info-circle-fill';
211→    }
212→  };
213→
214→  /**
215→   * Get toast background class
