229→
230→  return (
231→    <div className="user-mapping-manager">
232→      {/* Toast Container */}
233→      <div className="toast-container position-fixed top-0 end-0 p-3" style={{ zIndex: 9999 }}>
234→        {toasts.map((toast) => (
235→          <div
236→            key={toast.id}
237→            className={`toast show ${getToastBgClass(toast.type)} text-white`}
238→            role="alert"
239→            aria-live="assertive"
240→            aria-atomic="true"
241→          >
242→            <div className="toast-header">
243→              <i className={`bi ${getToastIcon(toast.type)} me-2`}></i>
244→              <strong className="me-auto">
245→                {toast.type.charAt(0).toUpperCase() + toast.type.slice(1)}
246→              </strong>
247→              <button
248→                type="button"
249→                className="btn-close"
250→                onClick={() => dismissToast(toast.id)}
251→                aria-label="Close"
252→              ></button>
253→            </div>
254→            <div className="toast-body">{toast.message}</div>
255→          </div>
256→        ))}
257→      </div>
258→
259→      {/* Page Header */}
260→      <div className="row mb-4">
261→        <div className="col">
262→          <h2 className="mb-1">User Mapping Management</h2>
263→          <p className="text-muted">
264→            Map users to AWS accounts and IP addresses for access control
265→          </p>
266→        </div>
267→      </div>
268→
269→      {/* Tabs */}
270→      <ul className="nav nav-tabs mb-4" role="tablist">
271→        <li className="nav-item" role="presentation">
272→          <button
273→            className={`nav-link ${activeTab === 'upload' ? 'active' : ''}`}
274→            onClick={() => setActiveTab('upload')}
275→            type="button"
276→            role="tab"
277→          >
