282→        <li className="nav-item" role="presentation">
283→          <button
284→            className={`nav-link ${activeTab === 'manage' ? 'active' : ''}`}
285→            onClick={() => setActiveTab('manage')}
286→            type="button"
287→            role="tab"
288→          >
