142→export async function downloadCSVTemplate(): Promise<void> {
143→  try {
144→    const response = await fetch('/api/import/user-mapping-template-csv', {
145→      method: 'GET',
146→      credentials: 'include', // Send HttpOnly auth cookie
147→    });
148→
149→    if (!response.ok) {
150→      if (response.status === 401) {
151→        throw new Error('Authentication required');
152→      } else if (response.status === 403) {
153→        throw new Error('Insufficient permissions (ADMIN role required)');
154→      } else {
155→        throw new Error(`Download failed with status ${response.status}`);
156→      }
157→    }
158→
159→    // Get the blob from response
160→    const blob = await response.blob();
161→
162→    // Create download link and trigger download
163→    const url = window.URL.createObjectURL(blob);
164→    const link = document.createElement('a');
165→    link.href = url;
166→    link.download = 'user-mapping-template.csv';
167→    document.body.appendChild(link);
168→    link.click();
169→
170→    // Cleanup
171→    document.body.removeChild(link);
172→    window.URL.revokeObjectURL(url);
173→  } catch (error) {
174→    if (error instanceof Error) {
175→      throw error;
176→    }
177→    throw new Error('Failed to download CSV template');
178→  }
